require_once dirname(__DIR__) . '/includes/cms.php';if($_SERVER['REQUEST_METHOD']!=='POST'||!validarTokenCsrf($_POST['csrf_token']??null)){cmsFlash('error','Solicitud o token CSRF inválido.');header('Location: index.php');exit;}$id=cmsId($_POST['id']??0);$accion=(string)($_POST['accion']??'');$pdo=obtenerConexion();if($id&&$accion==='toggle'){$q=$pdo->prepare('UPDATE menu_sitio SET activo=1-activo WHERE id=:id');$q->execute(['id'=>$id]);cmsFlash('exito','Estado actualizado.');}elseif($id&&$accion==='eliminar'){$q=$pdo->prepare('DELETE FROM menu_sitio WHERE id=:id');$q->execute(['id'=>$id]);cmsFlash('exito','Enlace eliminado.');}else cmsFlash('error','Acción inválida.');header('Location: index.php');exit;
